+func NormalizeCheckpointRunID(runID string) (string, error) {
+	runID = strings.TrimSpace(runID)
+	if runID == "" {
+		return "", errors.New("run ID is required")
+	}
+	if filepath.IsAbs(runID) || runID == "." || runID == ".." {
+		return "", fmt.Errorf("invalid run ID %q", runID)
